package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;
import java.lang.reflect.Field;

class GsonBuilderTest {

  @Test
  void testSerializeSpecialFloatingPointValues() throws Exception {
    GsonBuilder builder = new GsonBuilder();

    // Initially the field serializeSpecialFloatingPointValues should be false (default)
    Field field = GsonBuilder.class.getDeclaredField("serializeSpecialFloatingPointValues");
    field.setAccessible(true);
    boolean initialValue = (boolean) field.get(builder);
    assertFalse(initialValue);

    // Call the focal method
    GsonBuilder returned = builder.serializeSpecialFloatingPointValues();

    // The method should return the same builder instance (for chaining)
    assertSame(builder, returned);

    // The field serializeSpecialFloatingPointValues should now be true
    boolean updatedValue = (boolean) field.get(builder);
    assertTrue(updatedValue);
  }
}
